-- Vendedores e cobradores: apenas categorizar como Bronze (nao altera matriz existente).
UPDATE public.users
SET
  permissoes = COALESCE(permissoes, '{}'::jsonb) || jsonb_build_object('nivel_padrao', 'bronze'),
  updated_at = now()
WHERE role IN ('vendedor', 'cobrador')
  AND ativo = true
  AND deleted_at IS NULL
  AND (permissoes->>'nivel_padrao' IS NULL OR permissoes->>'nivel_padrao' IS DISTINCT FROM 'bronze');
